  `,r.querySelector(".help-modal").addEventListener("click",i=>i.stopPropagation()),r.addEventListener("click",closeHelpModal),r.querySelector(".help-modal-close").addEventListener("click",i=>{i.preventDefault(),closeHelpModal()}),r}function openHelpModal(e={}){isHelpModalOpen=!0,document.querySelector(".help-modal-backdrop")?.remove();const t=createHelpModal(e);t&&document.body.append(t)}function showInitialHelpIntro(){hasSeenHelpIntro()||window.requestAnimationFrame(()=>openHelpModal({intro:!0}))}function closeChangelogModal(){document.querySelector(".changelog-modal-backdrop")?.remove()}function openChangelogModal(){closeChangelogModal();const e=document.createElement("div");e.className="help-modal-backdrop changelog-modal-backdrop",e.innerHTML=`
